// condOrParts: pass the full condition object (preferred) or a condition name string.
// If no direct name-match found, falls back to organ-based matching using cond.parts[].
export function getMedicationsForCondition(condOrParts) {
  if (typeof condOrParts === 'string') {
    // Legacy string call — exact name match only
    return MEDICATIONS.filter(m => m.conditions && m.conditions.includes(condOrParts));
  }
  const cond = condOrParts;
  const byName = MEDICATIONS.filter(m => m.conditions && m.conditions.includes(cond.name));
  if (byName.length) return byName;
  // Fallback: any medication that covers at least one of the condition's parts
  if (!cond.parts || !cond.parts.length) return [];
  const partSet = new Set(cond.parts);
  return MEDICATIONS.filter(m => m.organs && m.organs.some(o => partSet.has(o))).slice(0, 8);
}

export function getMedicationsForOrgan(label) {
  return MEDICATIONS.filter(m => m.organs.includes(label));
}
